import React from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ancho,
  alto,
  ovaloRedondez = "9999px", // Un valor alto para asegurar que siempre sea un óvalo/cápsula
  cuadroRedondez,
}) => {
  // Las props dinámicas (ancho, alto, redondez) se mantienen en el objeto de estilo,
  // que es la práctica correcta en estos casos.
  const containerStyle = {
    width: ancho,
    height: alto,
    borderRadius: `${cuadroRedondez} 0 0 ${cuadroRedondez}`,
  };

  return (
    <div
      style={containerStyle}
      // REFACTORIZACIÓN A TAILWIND:
      // Usamos clases para el fondo, borde, sombra y layout principal.
      // `relative` es clave para posicionar el subtítulo correctamente.
      className="relative flex flex-col items-center justify-start bg-surface border-[0.4vh] border-primary shadow-xl mt-[5vh]"
    >
      {/* --- Subtítulo en Óvalo --- */}
      <div
        // Usamos clases para el fondo, borde, sombra y tipografía.
        className="absolute bg-surface border-[0.2vh] border-stroke shadow-md px-8 py-2 flex items-center justify-center z-10"
        style={{
          // Posicionamos el óvalo en el centro superior y lo desplazamos hacia arriba
          // para que se asiente sobre el borde del contenedor principal.
          top: 0,
          left: '50%',
          transform: 'translate(-50%, -50%)',
          borderRadius: ovaloRedondez,
        }}
      >
        <h2 className="font-bodoni text-primary text-xl sm:text-2xl whitespace-nowrap tracking-widest">
          {subtitulo}
        </h2>
      </div>

      {/* --- Contenido (Imagen) --- */}
      <div className="w-full h-full flex items-center justify-center p-8 pt-16">
        {/* El padding superior (pt-16) crea espacio para el título de forma natural */}
        <img
          src={imagen}
          alt="contenido dinámico"
          // Hacemos que la imagen llene el espacio disponible sin distorsionarse.
          className="w-full h-full object-contain"
          style={{
            borderRadius: cuadroRedondez,
          }}
        />
      </div>
    </div>
  );
};

export default ContenedorLateral;
